fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let bypass = required_bool(params, "bypass").map_err(anyhow::Error::msg)?;
    let level_in = required_f32(params, "level_in").map_err(anyhow::Error::msg)?;
    let level_out = required_f32(params, "level_out").map_err(anyhow::Error::msg)?;
    let mix = required_f32(params, "mix").map_err(anyhow::Error::msg)?;
    let attack_time = required_f32(params, "attack_time").map_err(anyhow::Error::msg)?;
    let attack_boost = required_f32(params, "attack_boost").map_err(anyhow::Error::msg)?;
    let sustain_threshold = required_f32(params, "sustain_threshold").map_err(anyhow::Error::msg)?;
    let release_time = required_f32(params, "release_time").map_err(anyhow::Error::msg)?;
    let release_boost = required_f32(params, "release_boost").map_err(anyhow::Error::msg)?;
    let display = required_f32(params, "display").map_err(anyhow::Error::msg)?;
    let display_threshold = required_f32(params, "display_threshold").map_err(anyhow::Error::msg)?;
    let lookahead = required_f32(params, "lookahead").map_err(anyhow::Error::msg)?;
    let view = required_f32(params, "view").map_err(anyhow::Error::msg)?;
    let hipass = required_f32(params, "hipass").map_err(anyhow::Error::msg)?;
    let lopass = required_f32(params, "lopass").map_err(anyhow::Error::msg)?;
    let hp_mode = required_f32(params, "hp_mode").map_err(anyhow::Error::msg)?;
    let lp_mode = required_f32(params, "lp_mode").map_err(anyhow::Error::msg)?;
    let listen = required_bool(params, "listen").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BYPASS, if bypass { 1.0 } else { 0.0 }),
        (PORT_CTRL_LEVEL_IN, level_in),
        (PORT_CTRL_LEVEL_OUT, level_out),
        (PORT_CTRL_MIX, mix),
        (PORT_CTRL_ATTACK_TIME, attack_time),
        (PORT_CTRL_ATTACK_BOOST, attack_boost),
        (PORT_CTRL_SUSTAIN_THRESHOLD, sustain_threshold),
        (PORT_CTRL_RELEASE_TIME, release_time),
        (PORT_CTRL_RELEASE_BOOST, release_boost),
        (PORT_CTRL_DISPLAY, display),
        (PORT_CTRL_DISPLAY_THRESHOLD, display_threshold),
        (PORT_CTRL_LOOKAHEAD, lookahead),
        (PORT_CTRL_VIEW, view),
        (PORT_CTRL_HIPASS, hipass),
        (PORT_CTRL_LOPASS, lopass),
        (PORT_CTRL_HP_MODE, hp_mode),
        (PORT_CTRL_LP_MODE, lp_mode),
        (PORT_CTRL_LISTEN, if listen { 1.0 } else { 0.0 }),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN_L, PORT_AUDIO_IN_IN_R], &[PORT_AUDIO_OUT_OUT_L, PORT_AUDIO_OUT_OUT_R], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

